import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './App.css';

const moviesData = [
  { 
    id: 1, 
    title: "Сны поездов", 
    poster: "https://statichdrezka.ac/i/2025/11/22/ve5f86e096f3ftl37o14l.jpg", 
    price: 350 
  },
  { 
    id: 2, 
    title: "Убойная суббота", 
    poster: "https://statichdrezka.ac/i/2025/10/28/w8e844c9cf3f4wn55f68z.jpg", 
    price: 400 
  },
  { 
    id: 3, 
    title: "Бугония", 
    poster: "https://statichdrezka.ac/i/2025/12/16/s2f9fa24dd993rl76z62e.jpg", 
    price: 300 
  },
  { 
    id: 4, 
    title: "Джокер", 
    poster: "https://m.media-amazon.com/images/M/MV5BNGVjNWI4ZGUtNzE0MS00YTJmLWE0ZDctN2ZiYTk2YmI3NTYyXkEyXkFqcGdeQXVyMTkxNjUyNQ@@._V1_.jpg", 
    price: 450 
  },
];

function MainPage() {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState(''); 

  const handleBuy = (movie) => {
    navigate('/create-order', { state: { movieTitle: movie.title, moviePrice: movie.price } });
  };

  const filteredMovies = moviesData.filter(movie => 
    movie.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="main-page">
      <h2>Популярные фильмы</h2>
      <div className="search-bar">
        <input 
          type="text" 
          placeholder="айти фильм..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="movie-list">
        {filteredMovies.length > 0 ? (
          filteredMovies.map((movie) => (
            <div key={movie.id} className="movie-card">
              <img src={movie.poster} alt={movie.title} />
              <h3>{movie.title}</h3>
              <p>Цена: {movie.price} сом</p>
              <div className="card-buttons">
                <Link to={`/movie/${movie.id}`} className="more-btn">Подробнее</Link>
                <button onClick={() => handleBuy(movie)} className="buy-btn">Купить</button>
              </div>
            </div>
          ))
        ) : (
          <p style={{textAlign: 'center', width: '100%'}}>Фильмы не найдены :(</p>
        )}
      </div>
    </div>
  );
}

export default MainPage;
